DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGchoicemacros.pl", "contextFiniteSolutionSets.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z'); Context()->variables->are($var => 'Real'); ($a, $b) = (2..20)[NchooseK(19,2)]; $b = random(0,1) ? $b : -$b; $left = Formula("$var/$a")->reduce; $right = Formula("$b")->reduce; ($left, $right) = ($left, $right)[NchooseK(2,2)]; Context("FiniteSolutionSets"); Context()->variables->are($var => 'Real'); $solution = $b*$a; $solset = Formula("{$solution}");
############################################################ # Body ############################################################
BEGIN_PGML Solve the equation.
[`[$left]=[$right]`]
[_]{$solset}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The opposite action to division is multiplication.
[```\newcommand{\multiplyleft}[2][\cdot]{{\highlight{{#2#1{}}}}}\newcommand{\amp}{&} \begin{aligned} [$left] \amp= [$right]\\ \multiplyleft{[$a]}[$left] \amp= \multiplyleft{[$a]}[$right]\\ [$var] \amp= [$solution] \end{aligned} ```]
The solution set is [`[$solset]\text{.}`]
END_PGML_SOLUTION
